import React, { useState, useEffect, useCallback } from 'react';
import { stationApi } from './api/stationApi';
import { auth } from './api/authApi';
import LoginPage from './components/LoginPage';
import StationForm from './components/StationForm';
import StationDetail from './components/StationDetail';
import ConfirmDialog from './components/ConfirmDialog';
import Toast from './components/Toast';
import StationGroupsPage from './components/StationGroupsPage';

const s = {
  app: { minHeight: '100vh', display: 'flex', flexDirection: 'column' },
  header: {
    background: 'linear-gradient(135deg, #0d3b6e 0%, #1a5fa8 100%)',
    padding: '0 32px', height: 64,
    display: 'flex', alignItems: 'center', justifyContent: 'space-between',
    boxShadow: '0 2px 12px rgba(13,59,110,0.3)',
    position: 'sticky', top: 0, zIndex: 100,
  },
  logo: { display: 'flex', alignItems: 'center', gap: 12 },
  logoIcon: {
    width: 38, height: 38, borderRadius: 10,
    background: 'rgba(255,255,255,0.15)',
    display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 18,
  },
  logoText: { color: '#fff', fontSize: 15, fontWeight: 700, lineHeight: 1.2 },
  logoSub: { color: 'rgba(255,255,255,0.65)', fontSize: 11 },
  tabsBar: {
    background: '#fff', borderBottom: '1px solid #ccd8e8',
    padding: '0 32px', display: 'flex', gap: 4,
    position: 'sticky', top: 64, zIndex: 99,
  },
  tab: (active) => ({
    padding: '14px 20px', fontSize: 13, fontWeight: 600,
    color: active ? '#0d3b6e' : '#7a94a8',
    background: 'transparent', border: 'none',
    borderBottom: active ? '3px solid #0d3b6e' : '3px solid transparent',
    cursor: 'pointer', transition: '0.15s',
    display: 'flex', alignItems: 'center', gap: 6, marginBottom: -1,
  }),
  main: { flex: 1, padding: '28px 32px', maxWidth: 1200, margin: '0 auto', width: '100%' },
  toolbar: {
    display: 'flex', alignItems: 'center', justifyContent: 'space-between',
    marginBottom: 20, gap: 12, flexWrap: 'wrap',
  },
  pageTitle: { fontSize: 20, fontWeight: 700, color: '#0d3b6e' },
  pageSub: { fontSize: 13, color: '#7a94a8', marginTop: 2 },
  searchBox: {
    display: 'flex', alignItems: 'center', gap: 8,
    background: '#fff', border: '1px solid #ccd8e8', borderRadius: 10,
    padding: '0 14px', height: 40, flex: '0 0 300px',
  },
  searchInput: {
    border: 'none', outline: 'none', background: 'transparent',
    fontSize: 13, color: '#12263a', flex: 1,
  },
  btnAdd: {
    display: 'flex', alignItems: 'center', gap: 7,
    padding: '0 20px', height: 40, borderRadius: 10,
    background: '#0d3b6e', color: '#fff', border: 'none',
    fontSize: 13, fontWeight: 700, cursor: 'pointer',
    whiteSpace: 'nowrap', transition: '0.15s',
  },
  statsRow: { display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 14, marginBottom: 24 },
  statCard: {
    background: '#fff', border: '1px solid #ccd8e8', borderRadius: 12,
    padding: '16px 20px', display: 'flex', alignItems: 'center', gap: 14,
  },
  statIcon: {
    width: 44, height: 44, borderRadius: 10,
    display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 20,
  },
  statNum: { fontSize: 26, fontWeight: 700, color: '#0d3b6e', lineHeight: 1 },
  statLabel: { fontSize: 12, color: '#7a94a8', marginTop: 3 },
  tableWrap: {
    background: '#fff', borderRadius: 14, border: '1px solid #ccd8e8',
    overflow: 'hidden', boxShadow: '0 1px 4px rgba(13,59,110,0.06)',
  },
  table: { width: '100%', borderCollapse: 'collapse' },
  th: {
    padding: '11px 16px', textAlign: 'left', fontSize: 11,
    fontWeight: 700, color: '#7a94a8', letterSpacing: '0.06em',
    textTransform: 'uppercase', background: '#f5f8fc',
    borderBottom: '1px solid #ccd8e8',
  },
  td: {
    padding: '13px 16px', fontSize: 13, color: '#12263a',
    borderBottom: '1px solid #edf2f7', verticalAlign: 'middle',
  },
  codeBadge: {
    display: 'inline-block', padding: '2px 10px', borderRadius: 6,
    background: '#e8f1fb', color: '#0d3b6e',
    fontSize: 12, fontWeight: 700, fontFamily: 'JetBrains Mono, monospace',
  },
  ftpBadge: {
    display: 'inline-flex', alignItems: 'center', gap: 4,
    padding: '2px 8px', borderRadius: 6,
    background: '#eaf7f0', color: '#1b7a4a', fontSize: 11, fontWeight: 600,
  },
  simBadge: (expired) => ({
    display: 'inline-flex', alignItems: 'center', gap: 4,
    padding: '2px 8px', borderRadius: 6, fontSize: 11, fontWeight: 600,
    background: expired ? '#fdecea' : '#eaf7f0',
    color: expired ? '#b5261e' : '#1b7a4a',
  }),
  actionBtn: (variant) => ({
    padding: '5px 12px', borderRadius: 7, border: 'none',
    fontSize: 12, fontWeight: 600, cursor: 'pointer',
    background: variant === 'edit' ? '#e8f1fb' : variant === 'delete' ? '#fdecea' : '#f5f8fc',
    color: variant === 'edit' ? '#1a5fa8' : variant === 'delete' ? '#b5261e' : '#3d5a72',
  }),
  empty: { textAlign: 'center', padding: '60px 20px', color: '#a8bdd4' },
  loading: { textAlign: 'center', padding: '60px 20px', color: '#1a5fa8', fontSize: 15 },
  error: {
    background: '#fdecea', color: '#b5261e', borderRadius: 10,
    padding: '14px 20px', marginBottom: 20, fontSize: 13,
    display: 'flex', alignItems: 'center', gap: 8,
  },
};

// Helper lấy địa chỉ rút gọn từ object Address
function getAddressShort(station) {
  const addr = station.Address?.VN || station.Address?.EN;
  if (!addr) return '—';
  return [addr.Ward, addr.District, addr.Province].filter(Boolean).join(', ') || '—';
}

// Helper kiểm tra SIM hết hạn
function isSimExpired(station) {
  const exp = station.SimCard?.ExpiredAt;
  return exp ? new Date(exp) < new Date() : false;
}

export default function App() {
  const [loggedIn, setLoggedIn] = useState(auth.isLoggedIn());
  const [activeTab, setActiveTab] = useState('stations');

  const [stations, setStations] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [search, setSearch] = useState('');

  const [formOpen, setFormOpen] = useState(false);
  const [editStation, setEditStation] = useState(null);
  const [detailOpen, setDetailOpen] = useState(false);
  const [detailStation, setDetailStation] = useState(null);
  const [confirmOpen, setConfirmOpen] = useState(false);
  const [deleteTarget, setDeleteTarget] = useState(null);
  const [toasts, setToasts] = useState([]);

  const toast = useCallback((message, type = 'success') => {
    const id = Date.now();
    setToasts(p => [...p, { id, message, type }]);
  }, []);
  const removeToast = useCallback((id) => setToasts(p => p.filter(t => t.id !== id)), []);

  const load = useCallback(async () => {
    setLoading(true); setError('');
    try {
      const data = await stationApi.getAll();
      // API trả { items: [...], page, page_size, total }
      const list = data?.items || data?.data || (Array.isArray(data) ? data : []);
      setStations(list);
    } catch (e) {
      if (e.message?.includes('401')) {
        auth.removeToken(); setLoggedIn(false); return;
      }
      setError('Không thể tải dữ liệu: ' + e.message);
    } finally { setLoading(false); }
  }, []);

  useEffect(() => {
    if (loggedIn && activeTab === 'stations') load();
  }, [loggedIn, activeTab, load]);

  if (!loggedIn) return <LoginPage onLogin={() => setLoggedIn(true)} />;

  // ── CRUD handlers ──────────────────────────────────────────────────────────
  const handleSave = async (payload) => {
    try {
      if (editStation) {
        await stationApi.update(editStation.StationID, payload);
        toast('Cập nhật trạm thành công!');
      } else {
        await stationApi.create(payload);
        toast('Thêm trạm thành công!');
      }
      setFormOpen(false); setEditStation(null);
      load();
    } catch (e) { toast('Lỗi: ' + e.message, 'error'); }
  };

  const handleDelete = async () => {
    try {
      await stationApi.delete(deleteTarget.StationID);
      toast('Đã xoá trạm ' + (deleteTarget.StationName?.VN || deleteTarget.StationID));
      setConfirmOpen(false); setDeleteTarget(null);
      load();
    } catch (e) { toast('Lỗi xoá: ' + e.message, 'error'); }
  };

  // ── Filter ─────────────────────────────────────────────────────────────────
  const filtered = stations.filter(st => {
    if (!search) return true;
    const q = search.toLowerCase();
    return [
      st.StationID,
      st.StationName?.VN,
      st.StationName?.EN,
      st.Region?.VN,
      st.Address?.VN?.Province,
      st.Address?.VN?.District,
      st.SimCard?.PhoneNumber,
      st.Project,
    ].some(v => v?.toLowerCase().includes(q));
  });

  const totalFtp = stations.reduce((sum, st) => sum + (st.ftp_list?.length || 0), 0);
  const simExpiredCount = stations.filter(isSimExpired).length;

  return (
    <div style={s.app}>
      <Toast toasts={toasts} remove={removeToast} />

      {/* Header */}
      <header style={s.header}>
        <div style={s.logo}>
          <div style={s.logoIcon}>🌦️</div>
          <div>
            <div style={s.logoText}>Trạm AWS Trung Bộ</div>
            <div style={s.logoSub}>Hệ thống quản lý cấu hình</div>
          </div>
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
          <button onClick={() => activeTab === 'stations' ? load() : window.location.reload()}
            title="Tải lại" style={{
              background: 'rgba(255,255,255,0.1)', border: '1px solid rgba(255,255,255,0.2)',
              color: '#fff', borderRadius: 8, padding: '6px 12px', cursor: 'pointer', fontSize: 14,
            }}>↺</button>
          <button onClick={auth.logout} style={{
            background: 'rgba(255,255,255,0.1)', border: '1px solid rgba(255,255,255,0.2)',
            color: '#fff', borderRadius: 8, padding: '6px 14px', cursor: 'pointer',
            fontSize: 13, fontWeight: 600, display: 'flex', alignItems: 'center', gap: 6,
          }}>🚪 Đăng xuất</button>
        </div>
      </header>

      {/* Tabs */}
      <div style={s.tabsBar}>
        <button style={s.tab(activeTab === 'stations')} onClick={() => setActiveTab('stations')}>
          📡 Trạm AWS
        </button>
        <button style={s.tab(activeTab === 'groups')} onClick={() => setActiveTab('groups')}>
          📁 Nhóm trạm
        </button>
      </div>

      <main style={s.main}>
        {activeTab === 'stations' ? (
          <>
            {/* Stats */}
            <div style={s.statsRow}>
              {[
                { icon: '📡', num: stations.length,    label: 'Tổng số trạm',      bg: '#e8f1fb' },
                { icon: '🖥️', num: totalFtp,           label: 'FTP Servers',        bg: '#eaf7f0' },
                { icon: '⚠️', num: simExpiredCount,    label: 'SIM hết hạn',        bg: '#fdecea' },
              ].map((st, i) => (
                <div key={i} style={s.statCard}>
                  <div style={{ ...s.statIcon, background: st.bg }}>{st.icon}</div>
                  <div>
                    <div style={s.statNum}>{st.num}</div>
                    <div style={s.statLabel}>{st.label}</div>
                  </div>
                </div>
              ))}
            </div>

            {/* Toolbar */}
            <div style={s.toolbar}>
              <div>
                <div style={s.pageTitle}>Danh sách trạm</div>
                <div style={s.pageSub}>Quản lý cấu hình trạm đo AWS – Khu vực Trung Bộ</div>
              </div>
              <div style={{ display: 'flex', gap: 10, alignItems: 'center' }}>
                <div style={s.searchBox}>
                  <span style={{ color: '#a8bdd4', fontSize: 15 }}>🔍</span>
                  <input
                    style={s.searchInput}
                    placeholder="Tìm mã, tên, tỉnh, SIM..."
                    value={search}
                    onChange={e => setSearch(e.target.value)}
                  />
                  {search && (
                    <button onClick={() => setSearch('')}
                      style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#a8bdd4', fontSize: 16 }}>✕</button>
                  )}
                </div>
                <button style={s.btnAdd}
                  onMouseEnter={e => e.currentTarget.style.background = '#1a5fa8'}
                  onMouseLeave={e => e.currentTarget.style.background = '#0d3b6e'}
                  onClick={() => { setEditStation(null); setFormOpen(true); }}>
                  + Thêm trạm
                </button>
              </div>
            </div>

            {error && (
              <div style={s.error}>
                <span>⚠</span>{error}
                <button onClick={load} style={{
                  marginLeft: 'auto', background: 'none', border: 'none',
                  color: '#b5261e', cursor: 'pointer', fontWeight: 600,
                }}>Thử lại</button>
              </div>
            )}

            {/* Table */}
            <div style={s.tableWrap}>
              {loading ? (
                <div style={s.loading}>⏳ Đang tải dữ liệu...</div>
              ) : filtered.length === 0 ? (
                <div style={s.empty}>
                  <div style={{ fontSize: 40, marginBottom: 12 }}>📭</div>
                  <div style={{ fontSize: 15, fontWeight: 600, marginBottom: 6 }}>
                    {search ? 'Không tìm thấy trạm phù hợp' : 'Chưa có trạm nào'}
                  </div>
                  <div style={{ fontSize: 13 }}>
                    {search ? 'Thử tìm với từ khoá khác' : 'Nhấn "+ Thêm trạm" để bắt đầu'}
                  </div>
                </div>
              ) : (
                <table style={s.table}>
                  <thead>
                    <tr>
                      {['STT', 'Mã trạm', 'Tên trạm', 'Khu vực / Địa chỉ', 'SIM Card', 'FTP', 'Thao tác'].map(h => (
                        <th key={h} style={s.th}>{h}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {filtered.map((st, i) => {
                      const expired = isSimExpired(st);
                      return (
                        <tr key={st.StationID || i}
                          style={{ transition: '0.12s' }}
                          onMouseEnter={e => e.currentTarget.style.background = '#f5f8fc'}
                          onMouseLeave={e => e.currentTarget.style.background = ''}>
                          <td style={{ ...s.td, color: '#a8bdd4', width: 50 }}>{i + 1}</td>
                          <td style={s.td}>
                            <span style={s.codeBadge}>{st.StationID}</span>
                          </td>
                          <td style={{ ...s.td, fontWeight: 600, maxWidth: 180 }}>
                            {st.StationName?.VN || st.StationName?.EN || '—'}
                            {st.StationName?.EN && st.StationName?.EN !== st.StationName?.VN && (
                              <div style={{ fontSize: 11, color: '#7a94a8', fontWeight: 400 }}>
                                {st.StationName.EN}
                              </div>
                            )}
                          </td>
                          <td style={{ ...s.td, color: '#3d5a72', maxWidth: 220 }}>
                            <div style={{ fontWeight: 600, color: '#12263a' }}>{st.Region?.VN || '—'}</div>
                            <div style={{ fontSize: 11, color: '#7a94a8', marginTop: 2 }}>
                              {getAddressShort(st)}
                            </div>
                          </td>
                          <td style={s.td}>
                            {st.SimCard?.PhoneNumber
                              ? <span style={s.simBadge(expired)}>
                                  {expired ? '⚠️' : '📱'} {st.SimCard.PhoneNumber}
                                </span>
                              : <span style={{ color: '#a8bdd4', fontSize: 12 }}>Chưa có</span>}
                          </td>
                          <td style={s.td}>
                            {st.ftp_list?.length > 0
                              ? <span style={s.ftpBadge}>⚡ {st.ftp_list.length} server</span>
                              : <span style={{ color: '#a8bdd4', fontSize: 12 }}>Chưa có</span>}
                          </td>
                          <td style={{ ...s.td, whiteSpace: 'nowrap' }}>
                            <div style={{ display: 'flex', gap: 6 }}>
                              <button style={s.actionBtn('view')}
                                onClick={() => { setDetailStation(st); setDetailOpen(true); }}>
                                👁 Xem
                              </button>
                              <button style={s.actionBtn('edit')}
                                onClick={() => { setEditStation(st); setFormOpen(true); }}>
                                ✏️ Sửa
                              </button>
                              <button style={s.actionBtn('delete')}
                                onClick={() => { setDeleteTarget(st); setConfirmOpen(true); }}>
                                🗑 Xoá
                              </button>
                            </div>
                          </td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              )}
            </div>
          </>
        ) : (
          <StationGroupsPage toast={toast} onAuthError={() => setLoggedIn(false)} />
        )}
      </main>

      {/* Modals */}
      <StationForm
        open={formOpen} station={editStation}
        onClose={() => { setFormOpen(false); setEditStation(null); }}
        onSave={handleSave}
      />
      <StationDetail
        open={detailOpen} station={detailStation}
        onClose={() => setDetailOpen(false)}
        onEdit={() => { setDetailOpen(false); setEditStation(detailStation); setFormOpen(true); }}
      />
      <ConfirmDialog
        open={confirmOpen}
        message={`Bạn có chắc muốn xoá trạm "${deleteTarget?.StationName?.VN}" (${deleteTarget?.StationID})?`}
        onConfirm={handleDelete}
        onCancel={() => { setConfirmOpen(false); setDeleteTarget(null); }}
      />
    </div>
  );
}
